import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String serializedObject = "rO0ABXNyABpqYXZhLmxhbmcuU3RyaW5nAAAAAAABAgAAeHA="; // Serialized object with malicious payload

        try {
            ByteArrayInputStream byteStream = new ByteArrayInputStream(Base64.getDecoder().decode(serializedObject));
            ObjectInputStream objectInput = new ObjectInputStream(byteStream);

            Object obj = objectInput.readObject();

            if (obj instanceof String) {
                System.out.println("Deserialized object: " + obj);
            }

            objectInput.close();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

